import{_ as s,o as i,c as e,ae as t}from"./chunks/framework.CyZiF_rV.js";const c=JSON.parse('{"title":"Номер KSeF – структура и валидация","description":"","frontmatter":{},"headers":[],"relativePath":"ru/faktury/numer-ksef.md","filePath":"ru/faktury/numer-ksef.md"}'),l={name:"ru/faktury/numer-ksef.md"};function n(r,a,o,h,p,d){return i(),e("div",null,[...a[0]||(a[0]=[t(`<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/faktury/numer-ksef.md" target="_blank" rel="noreferrer">faktury/numer-ksef.md</a></p></blockquote><h1 id="номер-ksef-–-структура-и-валидация" tabindex="-1">Номер KSeF – структура и валидация <a class="header-anchor" href="#номер-ksef-–-структура-и-валидация" aria-label="Permalink to &quot;Номер KSeF – структура и валидация&quot;">​</a></h1><p>Номер KSeF – это уникальный идентификатор счета-фактуры, присваиваемый системой. Всегда имеет длину <strong>35 символов</strong> и является глобально уникальным – однозначно идентифицирует каждую фактуру в KSeF.</p><h2 id="общая-структура-номера" tabindex="-1">Общая структура номера <a class="header-anchor" href="#общая-структура-номера" aria-label="Permalink to &quot;Общая структура номера&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>9999999999-RRRRMMDD-FFFFFFFFFFFF-FF</span></span></code></pre></div><p>Где:</p><ul><li><code>9999999999</code> – NIP продавца (10 цифр),</li><li><code>RRRRMMDD</code> – дата принятия счета-фактуры (год, месяц, день) к дальнейшей обработке,</li><li><code>FFFFFFFFFFFF</code> – техническая часть, состоящая из 12 символов в шестнадцатеричной записи, только [0–9 A–F], заглавные буквы,</li><li><code>FF</code> – контрольная сумма CRC-8 - 2 символа в шестнадцатеричной записи, только [0–9 A–F], заглавные буквы.</li></ul><h2 id="пример" tabindex="-1">Пример <a class="header-anchor" href="#пример" aria-label="Permalink to &quot;Пример&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5265877635-20250826-0100001AF629-AF</span></span></code></pre></div><ul><li><code>5265877635</code> - NIP продавца,</li><li><code>20250826</code> - дата принятия счета-фактуры к дальнейшей обработке,</li><li><code>0100001AF629</code> - техническая часть,</li><li><code>AF</code> - контрольная сумма CRC-8.</li></ul><h2 id="валидация-номера-ksef" tabindex="-1">Валидация номера KSeF <a class="header-anchor" href="#валидация-номера-ksef" aria-label="Permalink to &quot;Валидация номера KSeF&quot;">​</a></h2><p>Процесс валидации включает:</p><ol><li>Проверку, что номер имеет <strong>ровно 35 символов</strong>.</li><li>Разделение части данных (32 символа) и контрольной суммы (2 символа).</li><li>Вычисление контрольной суммы из части данных <strong>алгоритмом CRC-8</strong>.</li><li>Сравнение вычисленной суммы со значением, находящимся в номере.</li></ol><h2 id="алгоритм-crc-8" tabindex="-1">Алгоритм CRC-8 <a class="header-anchor" href="#алгоритм-crc-8" aria-label="Permalink to &quot;Алгоритм CRC-8&quot;">​</a></h2><p>Для вычисления контрольной суммы применяется алгоритм <strong>CRC-8</strong> с параметрами:</p><ul><li><strong>Полином:</strong> <code>0x07</code></li><li><strong>Начальное значение:</strong> <code>0x00</code></li><li><strong>Формат результата:</strong> 2-символьная шестнадцатеричная запись (HEX, заглавные буквы)</li></ul><p>Пример: если вычисленная контрольная сумма составляет <code>0x46</code>, к номеру KSeF будет добавлено <code>&quot;46&quot;</code>.</p><h2 id="пример-на-языке-c" tabindex="-1">Пример на языке C#: <a class="header-anchor" href="#пример-на-языке-c" aria-label="Permalink to &quot;Пример на языке C#:&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> KSeF</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Client</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Core</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> isValid</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KsefNumberValidator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IsValid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ksefNumber, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">out</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h2 id="пример-на-языке-java" tabindex="-1">Пример на языке Java: <a class="header-anchor" href="#пример-на-языке-java" aria-label="Permalink to &quot;Пример на языке Java:&quot;">​</a></h2><p><a href="https://github.com/CIRFMF/ksef-client-java/blob/main/demo-web-app/src/integrationTest/java/pl/akmf/ksef/sdk/OnlineSessionIntegrationTest.java" target="_blank" rel="noreferrer">OnlineSessionIntegrationTest.java</a></p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KSeFNumberValidator.ValidationResult result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KSeFNumberValidator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isValid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ksefNumber);</span></span></code></pre></div>`,22)])])}const g=s(l,[["render",n]]);export{c as __pageData,g as default};
